console.log("App is running...");

// Sample data for artifacts
const artifacts = [
  {
    name: "Terracotta Army",
    dynasty: "Qin Dynasty",
    image: "https://upload.wikimedia.org/wikipedia/commons/thumb/e/e9/Terra_Cotta_Warriors%2C_Xi'an%2C_China.jpg/330px-Terra_Cotta_Warriors%2C_Xi'an%2C_China.jpg",
    description: "The Terracotta Army is a collection of terracotta sculptures depicting the armies of Qin Shi Huang, the first Emperor of China."
  },
  {
    name: "Jade Burial Suit",
    dynasty: "Han Dynasty",
    image: "https://upload.wikimedia.org/wikipedia/commons/thumb/a/a4/Jade_Burial_Suit_of_Liu_Xiu.jpg/330px-Jade_Burial_Suit_of_Liu_Xiu.jpg",
    description: "The Jade Burial Suit is a suit made of pieces of jade in which royal members of the Han dynasty were buried."
  }
];

// Populate artifacts list on the list page
const artifactsList = document.getElementById("artifacts-list");

artifacts.forEach((artifact, index) => {
  const li = document.createElement("li");
  li.textContent = artifact.name;
  li.addEventListener("click", () => showDetailPage(index));
  artifactsList.appendChild(li);
});

// Show detail page with artifact details
const showDetailPage = (index) => {
  document.getElementById("artifact-name").textContent = artifacts[index].name;
  document.getElementById("artifact-dynasty").textContent = artifacts[index].dynasty;
  document.getElementById("artifact-image").src = artifacts[index].image;
  document.getElementById("artifact-description").textContent = artifacts[index].description;

  document.getElementById("list-page").style.display = "none";
  document.getElementById("detail-page").style.display = "block";
};

