js:
console.log("App is running...");

// Sample data for artifacts
const artifactsData = [
{
name: "Terracotta Army",
dynasty: "Qin Dynasty",
image: "https://en.wikipedia.org/wiki/Terracotta_Army#/media/File:Terracotta_Army_(29304606085).jpg",
description: "The Terracotta Army is a collection of terracotta sculptures depicting the armies of Qin Shi Huang, the first Emperor of China. It is a form of funerary art buried with the emperor in 210–209 BC.",
},
{
name: "Jade Burial Suit",
dynasty: "Han Dynasty",
image: "https://en.wikipedia.org/wiki/Jade_burial_suit#/media/File:Jade_burial_suit2.jpg",
description: "A jade burial suit was used in China from the Neolithic period to the Han dynasty as a burial garment made of jade. They were interred with the dead as grave goods, most often used on high-ranking members of the aristocracies."
}
];

// Display list of artifacts
const artifactsList = document.getElementById("artifactsList");

artifactsData.forEach((artifact, index) => {
const artifactItem = document.createElement("li");
artifactItem.innerHTML = `
<img src="${artifact.image}" alt="${artifact.name}">
<h3>${artifact.name}</h3>
<p><strong>Dynasty:</strong> ${artifact.dynasty}</p>
<p>${artifact.description}</p>`;

artifactItem.addEventListener("click", () => {
displayArtifactDetail(index);
});

artifactsList.appendChild(artifactItem);
});

// Display artifact detail
function displayArtifactDetail(index) {
const artifactDetail = document.getElementById("artifactDetail");
artifactDetail.style.display = "block";
artifactDetail.innerHTML = `
<img src="${artifactsData[index].image}" alt="${artifactsData[index].name}">
<h2>${artifactsData[index].name}</h2>
<p><strong>Dynasty:</strong> ${artifactsData[index].dynasty}</p>
<p>${artifactsData[index].description}</p>`;
}

